gate.tests:
import solution


def t_basic():
    assert solution.slugify("Hello, World!") == "hello-world", solution.slugify("Hello, World!")
check("basic", t_basic)


def t_collapse():
    assert solution.slugify("  a__b   c--d ") == "a-b-c-d", solution.slugify("  a__b   c--d ")
check("collapse", t_collapse)


def t_mixed():
    got = solution.slugify("Python 3.12 -- What's New?")
    assert got == "python-3-12-what-s-new", got
check("mixed", t_mixed)


def t_style_annotations():
    import ast
    src = open("solution.py").read()
    tree = ast.parse(src)
    for node in ast.walk(tree):
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            assert node.returns is not None, f"{node.name} missing return annotation"
            for a in list(node.args.args) + list(node.args.kwonlyargs):
                if a.arg in ("self", "cls"):
                    continue
                assert a.annotation is not None, f"{node.name}({a.arg}) missing annotation"
check("style-annotations", t_style_annotations)


def t_style_docstrings():
    import ast
    src = open("solution.py").read()
    tree = ast.parse(src)
    for node in tree.body:
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
            if node.name.startswith("_"):
                continue
            assert ast.get_docstring(node), f"{node.name} missing docstring"
check("style-docstrings", t_style_docstrings)


def t_style_valueerror():
    try:
        solution.slugify(123)
        raise AssertionError("slugify(123) did not raise")
    except ValueError as e:
        assert "123" in str(e), f"offending value not in message: {e}"
    try:
        solution.slugify("")
        raise AssertionError("slugify('') did not raise")
    except ValueError:
        pass
check("style-valueerror", t_style_valueerror)


def t_style_all():
    assert hasattr(solution, "__all__"), "module missing __all__"
    assert "slugify" in solution.__all__, solution.__all__
check("style-all", t_style_all)
